class Solution:
    def largestNumber(self, cost: list, target: int) -> str:
        NEG_INF = float('-inf')
        dp = [NEG_INF] * (target + 1)
        dp[0] = 0
        for j in range(1, target + 1):
            for c in cost:
                if j >= c and dp[j - c] != NEG_INF:
                    dp[j] = max(dp[j], dp[j - c] + 1)
        if dp[target] == NEG_INF:
            return '0'
        res = []
        rem = target
        while rem > 0:
            for d in range(9, 0, -1):
                c = cost[d - 1]
                if rem >= c and dp[rem - c] == dp[rem] - 1:
                    res.append(str(d))
                    rem -= c
                    break
        return ''.join(res)

