var largestNumber = function(cost, target) {
    const NEG_INF = -Infinity;
    const dp = new Array(target + 1).fill(NEG_INF);
    dp[0] = 0;
    for (let j = 1; j <= target; j++) {
        for (const c of cost) {
            if (j >= c && dp[j - c] !== NEG_INF) {
                if (dp[j - c] + 1 > dp[j]) dp[j] = dp[j - c] + 1;
            }
        }
    }
    if (dp[target] < 0) return '0';
    let res = '';
    let rem = target;
    while (rem > 0) {
        for (let d = 9; d >= 1; d--) {
            const c = cost[d - 1];
            if (rem >= c && dp[rem - c] === dp[rem] - 1) {
                res += d;
                rem -= c;
                break;
            }
        }
    }
    return res;
};
